#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""deploy_datafix.py — Phase 3.2 数据层 keystone 修复

根因: markets/proxy.py 只导出 inject_no_proxy, 但 api_china/line_items_china
      import 的是 ensure_no_proxy → import 静默失败落 NO-OP 兜底 → NO_PROXY
      从未注入 → AKShare 全程走系统TUN代理 → 东财ProxyError → current_price=0.

修复: 1) markets/proxy.py 新增 ensure_no_proxy() (幂等注入) + 白名单裸域兜底
      2) api_china.get_prices 加新浪兜底 (东财ProxyError时自动回退, 海外可达)

用法: 在项目根目录(含 src/)运行  ->  poetry run python deploy_datafix.py
回滚: 把 deploy_backup/<时间戳>/ 下的文件覆盖回去即可
"""
import base64, os, sys, shutil
from datetime import datetime

FILES = {
    'src/markets/proxy.py': "",
    'src/tools/api_china.py': "",
}

def main():
    root = os.getcwd()
    if not os.path.isdir(os.path.join(root, "src")):
        print("[FAIL] 请在项目根目录(含 src/)运行此脚本"); sys.exit(1)
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    bdir = os.path.join(root, "deploy_backup", ts)
    os.makedirs(bdir, exist_ok=True)
    for rel, b64 in FILES.items():
        dst = os.path.join(root, *rel.split("/"))
        if os.path.exists(dst):
            shutil.copy2(dst, os.path.join(bdir, rel.replace("/", "__")))
        os.makedirs(os.path.dirname(dst), exist_ok=True)
        data = base64.b64decode(b64)
        with open(dst, "wb") as f:
            f.write(data)
        print(f"[OK] 写入 {rel} ({len(data)} bytes)")
    print(f"[OK] 原文件已备份 -> deploy_backup/{ts}/")
    removed = 0
    for r, _, _ in os.walk(os.path.join(root, "src")):
        if r.endswith("__pycache__"):
            shutil.rmtree(r, ignore_errors=True); removed += 1
    print(f"[OK] 清理 {removed} 个 __pycache__ (防陈旧字节码)")
    verify(root)

def verify(root):
    print("-"*60); print("验证:")
    sys.path.insert(0, root)
    for m in [m for m in sys.modules if "markets.proxy" in m or "tools.api_china" in m]:
        del sys.modules[m]
    os.environ.pop("NO_PROXY", None); os.environ.pop("no_proxy", None)
    try:
        from src.markets import proxy as P
        assert hasattr(P, "ensure_no_proxy"), "ensure_no_proxy 缺失"
        P.ensure_no_proxy()
        assert "eastmoney.com" in os.environ.get("NO_PROXY", ""), "NO_PROXY 未注入"
        print("  [PASS] ensure_no_proxy 存在且成功注入 NO_PROXY")
    except Exception as e:
        print(f"  [FAIL] proxy 验证失败: {e}"); sys.exit(1)
    try:
        from src.tools import api_china as AC
        assert hasattr(AC, "_get_prices_df_with_fallback"), "fallback helper 缺失"
        print("  [PASS] get_prices 新浪兜底 helper 就位")
    except Exception as e:
        print(f"  [FAIL] api_china 验证失败: {e}"); sys.exit(1)
    # best-effort 真实抓取(需网络, 失败不阻断部署)
    try:
        prices = AC.get_prices("600519.SH", "2026-06-01", "2026-06-20")
        if prices:
            print(f"  [PASS] 真实抓取 600519: {len(prices)} 条, 最新收盘={prices[-1].close}")
            print("         ^ current_price 已复活, 决策链短路解除")
        else:
            print("  [WARN] 真实抓取返回空 (东财+新浪均无数据? 查网络/是否交易日)")
    except Exception as e:
        print(f"  [WARN] 真实抓取异常(可能网络/代理): {str(e)[:140]}")
    print("-"*60)
    print("[SUCCESS] 数据层 keystone 修复部署完成")
    print("下一步: 重启 web_app, 重跑 600519 — 应看到真实 current_price + 真实多空信号")

if __name__ == "__main__":
    main()
